 {"id":"brenner_bot-6u0z","title":"Task: Performance Benchmarks & Budgets","description":"# Goal
Establish performance benchmarks and enforce budgets in CI.

# Metrics to Track

## 1. Core Web Vitals
- **LCP** (Largest Contentful Paint): < 2.5s
- **FID** (First Input Delay): < 100ms
- **CLS** (Cumulative Layout Shift): < 0.1
- **TTFB** (Time to First Byte): < 200ms
- **FCP** (First Contentful Paint): < 1.8s

## 2. Bundle Size
- Main bundle: < 200KB (gzipped)
- Vendor bundle: < 150KB (gzipped)
- Total initial JS: < 400KB (gzipped)
- Critical CSS: < 50KB

## 3. Test Execution Time
- Unit tests: < 30s total
- E2E tests: < 5m total
- Single E2E test: < 30s average

# Implementation

## 1. Performance E2E Tests
```typescript
// e2e/performance.spec.ts
import { test, expect } from '@playwright/test';
import { collectPerformanceTiming } from './utils/network-logging';

test.describe('Performance', () => {
  const pages = [
    { path: '/', name: 'Home', lcpBudget: 2000 },
    { path: '/corpus', name: 'Corpus', lcpBudget: 2500 },
    { path: '/corpus/transcript-batch-1', name: 'Document', lcpBudget: 3000 },
  ];

  for (const { path, name, lcpBudget } of pages) {
    test(`${name} page meets performance budgets`, async ({ page }) => {
      // Start measuring
      await page.goto(path);

      // Collect metrics via Performance API
      const metrics = await page.evaluate(() => {
        const paint = performance.getEntriesByType('paint');
        const nav = performance.getEntriesByType('navigation')[0] as PerformanceNavigationTiming;

        return {
          fcp: paint.find(p => p.name === 'first-contentful-paint')?.startTime,
          ttfb: nav.responseStart - nav.requestStart,
          domContentLoaded: nav.domContentLoadedEventEnd - nav.startTime,
          load: nav.loadEventEnd - nav.startTime,
        };
      });

      // Get LCP via PerformanceObserver
      const lcp = await page.evaluate(() => {
        return new Promise<number>((resolve) => {
          new PerformanceObserver((list) => {
            const entries = list.getEntries();
            const lastEntry = entries[entries.length - 1];
            resolve(lastEntry.startTime);
          }).observe({ type: 'largest-contentful-paint', buffered: true });

          // Fallback timeout
          setTimeout(() => resolve(0), 10000);
        });
      });

      console.log(`${name} Performance:`, {
        ...metrics,
        lcp,
      });

      // Assert budgets
      expect(metrics.fcp).toBeLessThan(1800);
      expect(metrics.ttfb).toBeLessThan(200);
      expect(lcp).toBeLessThan(lcpBudget);
    });
  }

  test('search interaction is fast', async ({ page }) => {
    await page.goto('/corpus');

    const start = performance.now();
    await page.keyboard.press('Meta+k');
    await page.waitForSelector('[data-testid="spotlight-search"]');
    const openTime = performance.now() - start;

    expect(openTime).toBeLessThan(100); // < 100ms to open

    const searchStart = performance.now();
    await page.fill('[data-testid="search-input"]', 'brenner');
    await page.waitForSelector('[data-testid="search-result"]');
    const resultTime = performance.now() - searchStart;

    expect(resultTime).toBeLessThan(500); // < 500ms for results (including debounce)
  });
});
```

## 2. Bundle Size Tracking
```typescript
// scripts/check-bundle-size.ts
import { readFileSync, readdirSync } from 'fs';
import { gzipSync } from 'zlib';
import { join } from 'path';

const BUDGETS = {
  'main': 200 * 1024,
  'vendor': 150 * 1024,
  'total': 400 * 1024,
};

const buildDir = '.next/static/chunks';
const files = readdirSync(buildDir);

let totalSize = 0;
const sizes: Record<string, number> = {};

for (const file of files) {
  if (!file.endsWith('.js')) continue;

  const content = readFileSync(join(buildDir, file));
  const gzipped = gzipSync(content);
  const size = gzipped.length;

  totalSize += size;

  if (file.includes('main')) {
    sizes['main'] = (sizes['main'] || 0) + size;
  } else if (file.includes('framework') || file.includes('vendor')) {
    sizes['vendor'] = (sizes['vendor'] || 0) + size;
  }
}

sizes['total'] = totalSize;

console.log('Bundle sizes (gzipped):');
for (const [name, size] of Object.entries(sizes)) {
  const budget = BUDGETS[name];
  const status = size <= budget ? '✓' : '✗';
  const pct = ((size / budget) * 100).toFixed(1);
  console.log(`  ${status} ${name}: ${(size / 1024).toFixed(1)}KB (${pct}% of ${budget / 1024}KB budget)`);
}

const failed = Object.entries(sizes).some(
  ([name, size]) => BUDGETS[name] && size > BUDGETS[name]
);

if (failed) {
  process.exit(1);
}
```

## 3. CI Integration
```yaml
# .github/workflows/performance.yml
name: Performance
on: [push, pull_request]

jobs:
  perf:
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v4
      - run: bun install
      - run: bun run build

      - name: Check bundle size
        run: bun run bundle-size

      - name: Run performance tests
        run: bun run test:perf

      - name: Store metrics
        uses: benchmark-action/github-action-benchmark@v1
        with:
          tool: 'customSmallerIsBetter'
          output-file-path: perf-results.json
          github-token: \${{ secrets.GITHUB_TOKEN }}
          auto-push: true
```

